#include <set>
#include <algorithm>
using namespace std;

class ExamRoom {
    int N;
    set<int> seats;
public:
    ExamRoom(int n) : N(n) {}

    int seat() {
        if (seats.empty()) {
            seats.insert(0);
            return 0;
        }
        int maxDist = *seats.begin();
        int pos = 0;
        int prev = *seats.begin();
        for (auto it = next(seats.begin()); it != seats.end(); ++it) {
            int curr = *it;
            int mid = prev + (curr - prev) / 2;
            int dist = (curr - prev) / 2;
            if (dist > maxDist) {
                maxDist = dist;
                pos = mid;
            }
            prev = curr;
        }
        int lastDist = (N - 1) - *seats.rbegin();
        if (lastDist > maxDist) {
            maxDist = lastDist;
            pos = N - 1;
        }
        seats.insert(pos);
        return pos;
    }

    void leave(int p) {
        seats.erase(p);
    }
};
```
efficiency: HIGH
time complexity: O(k log k) per seat/leave, where k is the number of occupied seats
space complexity: O(k)
energy implications: LOW
explanation: Uses a balanced BST (set) to maintain occupied seats in sorted order. seat() scans adjacent pairs to find the largest gap, choosing the leftmost seat in case of ties. leave() simply erases the seat. Efficient for up to 10^4 calls.

